function renderStars(rating) {
  const full = Math.floor(rating)
  const half = rating % 1 >= 0.5
  let stars = '★'.repeat(full)
  if (half) stars += '☆'
  return stars.padEnd(5, '☆')
}

export default function MovieDetail() {
  const { id } = useParams()
  const { user } = useAuth()
  const [horarioSeleccionado, setHorarioSeleccionado] = useState(null)

  const peliculaId = parseInt(id)
  const pelicula = PELICULAS.find((p) => p.id === peliculaId)
  const similares = PELICULAS.filter((p) => p.id !== peliculaId).slice(0, 4)

  useEffect(() => {
    setHorarioSeleccionado(null)
    window.scrollTo({ top: 0, behavior: 'smooth' })
  }, [peliculaId])

  if (!pelicula) {
    return (
      <div style={{ padding: '4rem', textAlign: 'center', color: '#888' }}>
        <h2>Película no encontrada</h2>
        <Link to="/cartelera" style={{ color: '#e50914' }}>
          ← Volver a cartelera
        </Link>
      </div>
    )
  }

  return (
    <div
      key={pelicula.id}
      className="detail-page"
      style={{ '--bg-image': `url(${pelicula.fondo || pelicula.imagen})` }}
    >
      <div className="detail-layout">
        <div className="detail-hero-card">
          <div className="detail-hero">
            <motion.img
              key={`img-${pelicula.id}`}
              src={pelicula.imagen}
              alt={pelicula.titulo}
              className="detail-poster"
              initial={{ opacity: 0, x: -50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6 }}
              whileHover={{ scale: 1.03, rotate: 1 }}
            />

            <motion.div
              key={`info-${pelicula.id}`}
              className="detail-info"
              initial={{ opacity: 0, x: 50 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.6 }}
            >
              <motion.span
                className="detail-genero"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.2 }}
              >
                {pelicula.genero}
              </motion.span>

              <motion.h1
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3 }}
              >
                {pelicula.titulo}
              </motion.h1>

              <motion.div
                className="detail-rating"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.35 }}
              >
                <span className="stars">{renderStars(pelicula.rating)}</span>
                <span className="rating-number">{pelicula.rating.toFixed(1)}/5</span>
              </motion.div>

              <motion.div
                className="detail-tags"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.4 }}
              >
                <span>🕐 {pelicula.duracion}</span>
                <span>🎭 {pelicula.clasificacion}</span>
                <span>💰 S/. {pelicula.precio.toFixed(2)}</span>
                <span>🗣️ {pelicula.idioma}</span>
                <span>🎬 {pelicula.formato}</span>
                <span>{pelicula.estreno ? '🔥 Estreno' : '🎞️ En cartelera'}</span>
              </motion.div>

              <motion.p
                className="detail-desc"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.5 }}
              >
                {pelicula.descripcion}
              </motion.p>

              <motion.div
                className="detail-crew"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.6 }}
              >
                <p>
                  <strong>Director:</strong> {pelicula.director}
                </p>
                <p>
                  <strong>Reparto:</strong> {pelicula.reparto}
                </p>
              </motion.div>

              <motion.div
                className="horarios-section"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.7 }}
              >
                <h3>Horarios disponibles</h3>

                <div className="horarios-grid">
                  {pelicula.horarios.map((hora) => (
                    <button
                      key={hora}
                      className={`horario-btn ${horarioSeleccionado === hora ? 'activo' : ''}`}
                      onClick={() => setHorarioSeleccionado(hora)}
                    >
                      {hora}
                    </button>
                  ))}
                </div>

                <div className="reservar-wrap">
<Link
  to={
    user
      ? `/checkout/${pelicula.id}?horario=${horarioSeleccionado}`
      : '/login'
  }
  className="btn-reservar"
>
  {user
    ? horarioSeleccionado
      ? `Reservar para las ${horarioSeleccionado} →`
      : 'Selecciona un horario →'
    : 'Inicia sesión para comprar →'}
</Link>
                </div>
              </motion.div>
            </motion.div>
          </div>
        </div>

        <motion.section
          key={`trailer-${pelicula.id}`}
          className="trailer-section"
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.9 }}
        >
          <div className="section-header">
            <h2>Trailer oficial</h2>
            <span>Mira un adelanto antes de comprar</span>
          </div>

          <div className="trailer-frame">
            <iframe
              src={pelicula.trailer}
              title={`Trailer de ${pelicula.titulo}`}
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
              allowFullScreen
            />
          </div>
        </motion.section>

        <motion.section
          key={`similares-${pelicula.id}`}
          className="similares-section"
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 1 }}
        >
          <div className="section-header">
            <h2>Películas similares</h2>
            <span>También podrían interesarte</span>
          </div>

          <div className="similares-grid">
            {similares.map((p, i) => (
              <motion.div
                key={p.id}
                className="similar-card"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 1.05 + i * 0.08 }}
                whileHover={{ y: -6 }}
              >
                <Link to={`/pelicula/${p.id}`} className="similar-link">
                  <img src={p.imagen} alt={p.titulo} className="similar-img" />
                  <div className="similar-info">
                    <span className="similar-genero">{p.genero}</span>
                    <h4>{p.titulo}</h4>
                    <p>{p.duracion} • S/. {p.precio.toFixed(2)}</p>
                    <p>{p.idioma} • {p.formato}</p>
                  </div>
                </Link>
              </motion.div>
            ))}
          </div>
        </motion.section>
      </div>
    </div>
  )
}